qry:select.qry:xquery:
				for $r in sql('  
SELECT {%=#VAR:@c_columnas%}
FROM 
LIQ20_VAR_GR_CONC as V {%=#VAR:@c_tables %} {%=#VAR:@c_joins %}
WHERE
V.oi_tot_liq_per = {$SOURCE/@oi} 
and V.c_grupo = \'1\'

')/ROWS/ROW

				for $r in split('1;{%=./@sum%}')/ROWS/ROW,
$x in $SOURCE/VAR
join $r/@value INNER $x/@cod

				for $r in split('1;{%=./@res%}')/ROWS/ROW,
$x in $SOURCE/VAR
join $r/@value INNER $x/@cod
